}

const ProjectsPanel: React.FC<ProjectsPanelProps> = ({
  projects,
  folders,
  onLoadProject,
  onDeleteProject,
  onRenameProject,
  onNewProject,
  onMoveProject,
  onCreateFolder,
  onDeleteFolder,
  onRenameFolder,
  currentProjectId,
}) => {
  const [currentFolderId, setCurrentFolderId] = useState<string | null>(null);

  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState('');
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const [showHistoryId, setShowHistoryId] = useState<string | null>(null);

  // Drag and Drop State
  const [draggedProjectId, setDraggedProjectId] = useState<string | null>(null);
  const [dragOverFolderId, setDragOverFolderId] = useState<string | null>(null);

  // Derived state
  const currentFolder = folders.find(f => f.id === currentFolderId);
  const visibleProjects = projects.filter(p => p.folderId === (currentFolderId || undefined));

  // In root view, show folders. In folder view, usually don't show nested folders (keeping it 1 level deep for now)
  const visibleFolders = currentFolderId ? [] : folders;

  const handleStartEdit = (item: Project | Folder, e: React.MouseEvent) => {
    e.stopPropagation();
    setEditingId(item.id);
    setEditName(item.name);
  };

  const handleSaveEdit = (id: string, type: 'project' | 'folder') => {
    if (editName.trim()) {
      if (type === 'project') {
          onRenameProject(id, editName.trim());
      } else {
          onRenameFolder(id, editName.trim());
      }
    }
    setEditingId(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent, id: string, type: 'project' | 'folder') => {
    if (e.key === 'Enter') {
      handleSaveEdit(id, type);
    }
  };

  const toggleHistory = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setShowHistoryId(prev => prev === id ? null : id);
  };

  // DnD Handlers
  const handleDragStart = (e: React.DragEvent, projectId: string) => {
      setDraggedProjectId(projectId);
      e.dataTransfer.setData('projectId', projectId);
      e.dataTransfer.effectAllowed = 'move';
      // Create a drag image if needed, or default is fine
  };

  const handleDragOver = (e: React.DragEvent, folderId: string | null) => {
      e.preventDefault();
      // Only allow dropping if we are dragging a project
      if (draggedProjectId) {
          setDragOverFolderId(folderId || 'root'); // 'root' for back button drop
          e.dataTransfer.dropEffect = 'move';
      }
  };

  const handleDragLeave = (e: React.DragEvent) => {
      e.preventDefault();
      setDragOverFolderId(null);
  };

  const handleDrop = (e: React.DragEvent, folderId: string | undefined) => {
      e.preventDefault();
      const projectId = e.dataTransfer.getData('projectId');
      if (projectId && projectId === draggedProjectId) {
          // Prevent dropping on self or same folder
          const project = projects.find(p => p.id === projectId);
          if (project && project.folderId !== folderId) {
             onMoveProject(projectId, folderId);
          }
      }
      setDraggedProjectId(null);
      setDragOverFolderId(null);
  };

  const handleDropOnRoot = (e: React.DragEvent) => {
      handleDrop(e, undefined); // undefined = root
  };

  return (
    <div className="h-full flex flex-col bg-[#09090b]">
      {/* Header */}
      <div className="px-6 py-2 border-b border-white/5 flex justify-between items-center bg-[#09090b]">
        <div className="flex items-center gap-4">
            {currentFolderId ? (
                <div 
                    className={`flex items-center gap-2 text-zinc-400 hover:text-white transition-colors cursor-pointer ${dragOverFolderId === 'root' ? 'bg-white/10 rounded px-2 -ml-2' : ''}`}
                    onClick={() => setCurrentFolderId(null)}
                    onDragOver={(e) => handleDragOver(e, null)}
                    onDragLeave={handleDragLeave}
                    onDrop={handleDropOnRoot}
                >
                    <div className="bg-zinc-800 p-1 rounded-md">
                        <CornerUpLeft size={12} />
                    </div>
                    <span className="text-[11px] font-bold uppercase tracking-widest">Back to Projects</span>
                </div>
            ) : (
                <h3 className="text-[11px] font-bold uppercase tracking-widest text-zinc-500">Projects</h3>
            )}

            <span className="text-[10px] text-zinc-700">|</span>

            <div className="flex items-center gap-2">
                <button 
                    onClick={() => onNewProject(currentFolderId || undefined)}
                    className="flex items-center gap-1.5 text-xs font-medium text-brand-400 hover:text-brand-300 transition-colors bg-brand-900/10 px-2 py-1 rounded-md border border-brand-500/10 hover:border-brand-500/30"
                    title="Create New Project"
                >
                    <Plus size={12} strokeWidth={3} />
                    Project
                </button>

                {!currentFolderId && (
                    <button 
                        onClick={onCreateFolder}
                        className="flex items-center gap-1.5 text-xs font-medium text-zinc-400 hover:text-white transition-colors bg-white/5 px-2 py-1 rounded-md border border-white/5 hover:bg-white/10"
                        title="Create New Folder"
                    >
                        <FolderIcon size={12} strokeWidth={3} />
                        Folder
                    </button>
                )}
            </div>
        </div>

        <div className="flex items-center gap-3">
             {currentFolderId && (
                 <div className="flex items-center gap-2 text-zinc-500 text-xs px-2 py-0.5 bg-white/5 rounded-full border border-white/5">
                     <FolderOpen size={10} />
                     <span className="font-medium text-zinc-300">{currentFolder?.name}</span>
                 </div>
             )}
             <span className="text-[11px] text-zinc-600 font-medium">
                 {visibleProjects.length} projects {visibleFolders.length > 0 && `• ${visibleFolders.length} folders`}
             </span>
        </div>
      </div>

      {/* List */}
      {(visibleProjects.length === 0 && visibleFolders.length === 0) ? (
        <div className="flex-1 flex flex-col items-center justify-center text-zinc-600 p-4">
            <div className="bg-white/5 p-4 rounded-full mb-3 ring-1 ring-white/5">
                {currentFolderId ? <FolderOpen className="w-5 h-5 opacity-40" /> : <ImageIcon className="w-5 h-5 opacity-40" />}
            </div>
            <p className="text-xs font-medium">
                {currentFolderId ? "This folder is empty." : "Your library is empty."}
            </p>
            {currentFolderId && (
                <button 
                    onClick={() => setCurrentFolderId(null)} 
                    className="mt-3 text-[10px] text-blue-400 hover:underline"
                >
                    Return to root
                </button>
            )}
        </div>
      ) : (
        <div className="flex-1 overflow-x-auto p-4 flex gap-4 overflow-y-hidden scrollbar-thin scrollbar-thumb-zinc-800 scrollbar-track-transparent items-center">

            {/* RENDER FOLDERS */}
            {visibleFolders.map(folder => (
                <div
                    key={folder.id}
                    onClick={() => setCurrentFolderId(folder.id)}
                    onDragOver={(e) => handleDragOver(e, folder.id)}
                    onDragLeave={handleDragLeave}
                    onDrop={(e) => handleDrop(e, folder.id)}
                    className={`
                        group relative flex-shrink-0 w-32 h-32 md:w-40 md:h-40 bg-[#141415] border rounded-xl cursor-pointer transition-all duration-300 flex flex-col items-center justify-center
                        ${dragOverFolderId === folder.id ? 'border-brand-500 bg-brand-500/10 scale-105' : 'border-white/5 hover:border-white/20 hover:bg-white/5 hover:-translate-y-1'}
                    `}
                >
                    <div className="relative mb-2">
                        <FolderIcon 
                            size={40} 
                            className={`text-zinc-600 fill-zinc-800/50 group-hover:text-zinc-500 transition-colors ${dragOverFolderId === folder.id ? 'text-brand-500' : ''}`} 
                            strokeWidth={1}
                        />
                        {/* Project count badge */}
                        <div className="absolute -bottom-1 -right-2 bg-zinc-800 text-zinc-400 text-[9px] px-1.5 rounded-full border border-zinc-700 min-w-[18px] text-center">
                            {projects.filter(p => p.folderId === folder.id).length}
                        </div>
                    </div>

                    {editingId === folder.id ? (
                        <input
                            type="text"
                            value={editName}
                            onChange={(e) => setEditName(e.target.value)}
                            onBlur={() => handleSaveEdit(folder.id, 'folder')}
                            onKeyDown={(e) => handleKeyDown(e, folder.id, 'folder')}
                            autoFocus
                            onClick={(e) => e.stopPropagation()}
                            className="w-24 bg-black text-white text-xs px-2 py-1 rounded border border-brand-500 outline-none text-center"
                        />
                    ) : (
                        <span className="text-xs font-medium text-zinc-400 group-hover:text-zinc-200 truncate max-w-[80%] text-center">
                            {folder.name}
                        </span>
                    )}

                    {/* Actions Overlay */}
                    <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity flex gap-1">
                        <button
                            onClick={(e) => handleStartEdit(folder, e)}
                            className="p-1.5 rounded-md bg-black/50 hover:bg-white/20 text-zinc-400 hover:text-white backdrop-blur-sm"
                        >
                            <Edit2 size={10} />
                        </button>
                        <button
                            onClick={(e) => {
                                e.stopPropagation();
                                if (deleteConfirmId === folder.id) {
                                    onDeleteFolder(folder.id);
                                    setDeleteConfirmId(null);
                                } else {
                                    setDeleteConfirmId(folder.id);
                                    setTimeout(() => setDeleteConfirmId(prev => prev === folder.id ? null : prev), 3000);
                                }
                            }}
                            className={`p-1.5 rounded-md transition-all backdrop-blur-sm ${
                                deleteConfirmId === folder.id ? 'bg-red-600 text-white' : 'bg-black/50 hover:bg-red-500/20 text-zinc-400 hover:text-red-400'
                            }`}
                        >
                            <Trash2 size={10} />
                        </button>
                    </div>
                </div>
            ))}

            {/* RENDER PROJECTS */}
            {visibleProjects.map((project) => (
            <div 
                key={project.id}
                draggable
                onDragStart={(e) => handleDragStart(e, project.id)}
                onClick={() => onLoadProject(project)}
                className={`
                group relative flex-shrink-0 w-60 aspect-video bg-[#1C1C1E] border rounded-xl overflow-hidden cursor-pointer transition-all duration-300
                ${currentProjectId === project.id 
                    ? 'border-brand-500/50 ring-2 ring-brand-500/20 shadow-md shadow-black' 
                    : 'border-white/5 hover:border-white/20 hover:-translate-y-1'
                }
                ${draggedProjectId === project.id ? 'opacity-50' : ''}
                `}
            >
                {/* Thumbnail Preview */}
                <div className="w-full h-full relative flex items-center justify-center bg-black">
                {(!project.thumbnail || project.thumbnail === PLACEHOLDER_THUMBNAIL) ? (
                     <div className="w-full h-full bg-[#1C1C1E] flex items-center justify-center">
                         <div className="flex flex-col items-center gap-2 opacity-30">
                            <Plus className="w-8 h-8 text-zinc-500" />
                         </div>
                     </div>
                ) : (
                    <img 
                        src={project.thumbnail} 
                        alt={project.name} 
                        className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity duration-500"
                    />
                )}

                <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-80 pointer-events-none" />
                </div>

                {/* History Overlay */}
                {showHistoryId === project.id && (
                    <div className="absolute inset-0 bg-black/90 backdrop-blur-sm z-30 flex flex-col animate-in fade-in duration-200 cursor-default" onClick={e => e.stopPropagation()}>
                        <div className="flex items-center justify-between p-2 border-b border-white/10">
                            <span className="text-[10px] font-bold uppercase text-zinc-400">Edit History</span>
                            <button 
                                onClick={(e) => toggleHistory(e, project.id)}
                                className="text-zinc-500 hover:text-white"
                            >
                                <X size={12} />
                            </button>
                        </div>
                        <div className="flex-1 overflow-y-auto p-2 space-y-2 scrollbar-thin scrollbar-thumb-zinc-700">
                            {(!project.editLog || project.editLog.length === 0) ? (
                                <p className="text-[10px] text-zinc-600 text-center mt-4">No history available</p>
                            ) : (
                                project.editLog.map((log) => (
                                    <div key={log.id} className="flex flex-col gap-0.5 pb-2 border-b border-white/5 last:border-0">
                                        <div className="flex justify-between items-center">
                                            <span className="text-[10px] font-semibold text-brand-400">{log.action}</span>
                                            <span className="text-[9px] text-zinc-600">{new Date(log.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                                        </div>
                                        {log.details && (
                                            <p className="text-[9px] text-zinc-400 truncate leading-tight" title={log.details}>
                                                {log.details}
                                            </p>
                                        )}
                                    </div>
                                ))
                            )}
                        </div>
                    </div>
                )}

                {/* Info Overlay */}
                <div className="absolute inset-x-0 bottom-0 p-3 pt-8 bg-gradient-to-t from-black/90 to-transparent">
                    <div className="flex justify-between items-end">
                        <div className="flex-1 mr-2 min-w-0">
                        {editingId === project.id ? (
                            <input
                            type="text"
                            value={editName}
                            onChange={(e) => setEditName(e.target.value)}
                            onBlur={() => handleSaveEdit(project.id, 'project')}
                            onKeyDown={(e) => handleKeyDown(e, project.id, 'project')}
                            autoFocus
                            onClick={(e) => e.stopPropagation()}
                            className="w-full bg-black text-white text-xs px-2 py-1 rounded border border-brand-500 outline-none"
                            />
                        ) : (
                            <div className="group/title flex items-center gap-2">
                            <h4 className="font-medium text-white text-xs truncate" title={project.name}>
                                {project.name}
                            </h4>
                            <button 
                                onClick={(e) => handleStartEdit(project, e)}
                                className="opacity-0 group-hover/title:opacity-100 text-zinc-400 hover:text-white transition-opacity"
                            >
                                <Edit2 size={10} />
                            </button>
                            </div>
                        )}
                        <div className="flex items-center gap-1.5 text-[10px] text-zinc-500 mt-1">
                            <Clock size={10} />
                            <span>{new Date(project.timestamp).toLocaleDateString()}</span>
                        </div>
                        </div>

                        <div className="flex items-center gap-1">
                             <button
                                onClick={(e) => toggleHistory(e, project.id)}
                                className={`p-2 rounded-full transition-all backdrop-blur-md z-20 ${
                                    showHistoryId === project.id 
                                    ? 'bg-brand-500 text-white' 
                                    : 'bg-white/5 hover:bg-white/20 text-zinc-400 hover:text-brand-300 opacity-0 group-hover:opacity-100'
                                }`}
                                title="View History"
                            >
                                <History size={12} strokeWidth={2} />
                            </button>

                            <button
                                onClick={(e) => {
                                    e.stopPropagation();
                                    if (deleteConfirmId === project.id) {
                                        onDeleteProject(project.id);
                                        setDeleteConfirmId(null);
                                    } else {
                                        setDeleteConfirmId(project.id);
                                        setTimeout(() => setDeleteConfirmId(prev => prev === project.id ? null : prev), 3000);
                                    }
                                }}
                                className={`p-2 rounded-full transition-all backdrop-blur-md z-20 ${
                                    deleteConfirmId === project.id
                                    ? 'bg-red-600 text-white opacity-100 scale-110 shadow-lg shadow-red-900/50'
                                    : 'bg-white/5 hover:bg-red-500/20 text-zinc-400 hover:text-red-400 opacity-0 group-hover:opacity-100'
                                }`}
                                title={deleteConfirmId === project.id ? "Click again to delete" : "Delete"}
                            >
                                <Trash2 size={12} strokeWidth={deleteConfirmId === project.id ? 2.5 : 2} />
                            </button>
                        </div>
                    </div>
                </div>
            </div>
            ))}
        </div>
      )}
    </div>
  );
};

export default ProjectsPanel;

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import ChatSidebar from './components/ChatSidebar';
import ImageArea from './components/ImageArea';
import ProjectsPanel from './components/ProjectsPanel';
import { Message, Project, EditLogEntry, HistoryItem, Region, Folder } from './types';
import { editImageWithGemini, analyzeImage, chatWithGemini } from './services/geminiService';
import { getAllProjects, saveProjectToDB, deleteProjectFromDB, getAllFolders, saveFolderToDB, deleteFolderFromDB } from './services/db';
import { Zap, Loader2, Settings, LogOut, User as UserIcon, ChevronDown, Undo2, Redo2 } from 'lucide-react';
import { PLACEHOLDER_THUMBNAIL } from './constants';

const App: React.FC = () => {
  // --- State ---
  // Project & Persistence
  const [projects, setProjects] = useState<Project[]>([]);
  const [folders, setFolders] = useState<Folder[]>([]);
  const [isProjectsLoading, setIsProjectsLoading] = useState(true);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);

  // Editor State
  const [currentImage, setCurrentImage] = useState<string | null>(null);
  const [autoAnalyzeEnabled, setAutoAnalyzeEnabled] = useState(true); // Default to true
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [selectedRegion, setSelectedRegion] = useState<Region | null>(null);

  // Layout State
  const [sidebarWidth, setSidebarWidth] = useState(400);
  const [isResizing, setIsResizing] = useState(false);

  // History now stores rich objects
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  const [messages, setMessages] = useState<Message[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);

  // UI State
  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const [toast, setToast] = useState<{message: string, icon?: React.ReactNode} | null>(null);

  // Visual Feedback for Undo/Redo
  const [visualFeedback, setVisualFeedback] = useState<{ type: 'undo' | 'redo', label: string } | null>(null);

  // Refs for safe access inside async callbacks
  const historyRef = useRef(history);
  const historyIndexRef = useRef(historyIndex);
  const currentProjectIdRef = useRef(currentProjectId);
  const messagesRef = useRef(messages);

  // Ref to track the current generation ID for cancellation
  const generationIdRef = useRef(0);

  // Update refs whenever state changes
  useEffect(() => {
    historyRef.current = history;
    historyIndexRef.current = historyIndex;
  }, [history, historyIndex]);

  useEffect(() => {
    messagesRef.current = messages;
  }, [messages]);

  useEffect(() => {
    currentProjectIdRef.current = currentProjectId;
  }, [currentProjectId]);

  // --- Effects ---

  // 1. Cleanup legacy localStorage to prevent QuotaExceededError
  useEffect(() => {
    try {
      if (localStorage.getItem('tubethumb_projects')) {
        console.log('Cleaning up legacy localStorage data...');
        localStorage.removeItem('tubethumb_projects');
      }
    } catch (e) {
      // Ignore errors if localStorage is blocked
    }
  }, []);

  // 2. Load projects and folders from IndexedDB on mount
  useEffect(() => {
    const loadData = async () => {
      try {
        const [loadedProjects, loadedFolders] = await Promise.all([
             getAllProjects(),
             getAllFolders()
        ]);

        // Ensure all loaded projects have an editLog array (migration for existing projects)
        const projectsWithLog = loadedProjects.map(p => ({
            ...p,
            editLog: p.editLog || []
        }));

        setProjects(projectsWithLog);
        setFolders(loadedFolders);
      } catch (error) {
        console.error("Failed to load data from DB:", error);
      } finally {
        setIsProjectsLoading(false);
      }
    };
    loadData();
  }, []);

  // 3. Resizing Logic
  const startResizing = useCallback(() => setIsResizing(true), []);
  const stopResizing = useCallback(() => setIsResizing(false), []);

  const resize = useCallback(
    (mouseMoveEvent: MouseEvent) => {
        if (isResizing) {
            const newWidth = document.body.clientWidth - mouseMoveEvent.clientX;
            // Constraints: Min 300px, Max 50% of screen or 800px
            if (newWidth > 300 && newWidth < Math.min(800, document.body.clientWidth * 0.6)) {
                setSidebarWidth(newWidth);
            }
        }
    },
    [isResizing]
  );

  useEffect(() => {
    window.addEventListener("mousemove", resize);
    window.addEventListener("mouseup", stopResizing);
    return () => {
        window.removeEventListener("mousemove", resize);
        window.removeEventListener("mouseup", stopResizing);
    };
  }, [resize, stopResizing]);

  // --- Helpers ---

  const showToast = (message: string, icon?: React.ReactNode) => {
    setToast({ message, icon });
    setTimeout(() => setToast(null), 2500);
  };

  const showVisualFeedback = (type: 'undo' | 'redo', label: string) => {
      setVisualFeedback({ type, label });
      setTimeout(() => setVisualFeedback(null), 1500);
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = (error) => reject(error);
    });
  };

  const addToHistory = (image: string, action: string) => {
    const currentHist = historyRef.current;
    const currentIndex = historyIndexRef.current;

    // Slice history if we are in the middle of the stack
    const newHistory = currentHist.slice(0, currentIndex + 1);

    newHistory.push({
        id: uuidv4(),
        thumbnail: image,
        action: action,
        timestamp: Date.now()
    });

    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
    return { newHistory, newIndex: newHistory.length - 1 };
  };

  /**
   * Centralized function to update project state and persistence.
   * Handles updating the thumbnail, timestamp, persistence fields, and edit log.
   */
  const updateProjectState = async (
      projectId: string, 
      updates: Partial<Project>,
      logEntry?: Omit<EditLogEntry, 'id' | 'timestamp'>
  ) => {
      setProjects(prev => {
          const projectIndex = prev.findIndex(p => p.id === projectId);
          if (projectIndex === -1) return prev;

          const existingProject = prev[projectIndex];

          // Create new log entry if provided
          const newLog: EditLogEntry[] = logEntry ? [
              {
                  id: uuidv4(),
                  timestamp: Date.now(),
                  action: logEntry.action,
                  details: logEntry.details
              },
              ...existingProject.editLog
          ] : existingProject.editLog;

          const updatedProject: Project = {
              ...existingProject,
              ...updates,
              timestamp: Date.now(),
              editLog: newLog
          };

          // Async save to DB
          saveProjectToDB(updatedProject).catch(err => {
              console.error("Failed to save project state:", err);
          });

          // Return new array with updated project at the top (most recent)
          // Maintain folder view structure by not changing array order drastically or handle sort elsewhere?
          // Projects panel sorts by timestamp, so top is fine.
          const newProjects = [...prev];
          newProjects.splice(projectIndex, 1);
          return [updatedProject, ...newProjects];
      });
  };

  // --- Handlers ---

  const handleAnalyzeImage = async (imageOverride?: string, projectIdOverride?: string, styleContext?: string) => {
    const imgToAnalyze = imageOverride || currentImage;
    const activeProject = projectIdOverride || currentProjectId;

    if (!imgToAnalyze || !activeProject) return;

    // Increment generation ID
    const currentGenId = ++generationIdRef.current;
    setIsGenerating(true);
    setIsAnalyzing(true);

    // Add placeholder analysis message
    const tempId = uuidv4();
    const tempMsg: Message = {
        id: tempId,
        role: 'model',
        text: 'Analyzing your thumbnail for improvements...',
        timestamp: Date.now()
    };
    setMessages(prev => [...prev, tempMsg]);

    try {
        const analysis = await analyzeImage(imgToAnalyze, styleContext);

        if (currentGenId !== generationIdRef.current) return;

        // Remove temp message and add real response
        setMessages(prev => {
            const filtered = prev.filter(m => m.id !== tempId);
            const analysisMsg: Message = {
                id: uuidv4(),
                role: 'model',
                text: analysis.critique,
                suggestions: analysis.suggestions,
                timestamp: Date.now()
            };
            const newMessages = [...filtered, analysisMsg];

            // Persist
            updateProjectState(activeProject, { messages: newMessages });

            return newMessages;
        });

    } catch (error: any) {
        console.error("Analysis Error:", error);

        if (currentGenId === generationIdRef.current) {
             const errorMsg: Message = {
                 id: uuidv4(),
                 role: 'model',
                 text: "Failed to analyze image. Please check your connection and try again.",
                 timestamp: Date.now()
             };
             setMessages(prev => [...prev.filter(m => m.id !== tempId), errorMsg]);
        }
    } finally {
        if (currentGenId === generationIdRef.current) {
            setIsGenerating(false);
            setIsAnalyzing(false);
        }
    }
  };

  const handleImageUpload = async (file: File, template?: string) => {
    try {
      const base64 = await fileToBase64(file);

      let projectId = currentProjectId;
      let projectToUpdate = projects.find(p => p.id === projectId);
      let isNewOrReset = false;

      if (!projectId) {
          // Case 1: Create new project if none exists (Root Level)
          projectId = uuidv4();
          isNewOrReset = true;

          const initialHistory = [{ id: uuidv4(), thumbnail: base64, action: 'Initial Upload', timestamp: Date.now() }];
          const initialMessages: Message[] = [{ 
            id: uuidv4(), 
            role: 'model', 
            text: template 
              ? `Project started with **${template}**! I'll help you create that look.` 
              : 'Project started! What would you like to change?', 
            timestamp: Date.now() 
          }];

          const newProject: Project = {
            id: projectId,
            name: `Project ${projects.length + 1}`,
            thumbnail: base64,
            timestamp: Date.now(),
            editLog: [{
                id: uuidv4(),
                timestamp: Date.now(),
                action: 'Created',
                details: template ? `Uploaded base image (${template})` : 'Initial upload'
            }],
            history: initialHistory,
            historyIndex: 0,
            messages: initialMessages
          };
          await saveProjectToDB(newProject);
          setProjects(prev => [newProject, ...prev]);
          setCurrentProjectId(projectId);

          setCurrentImage(base64);
          setHistory(initialHistory);
          setHistoryIndex(0);
          setMessages(initialMessages);

      } else if (projectToUpdate && (projectToUpdate.thumbnail === PLACEHOLDER_THUMBNAIL)) {
          // Case 2: Update placeholder project (First real upload)
          isNewOrReset = true;
          const initialHistory = [{ id: uuidv4(), thumbnail: base64, action: 'Initial Upload', timestamp: Date.now() }];
          const initialMessages: Message[] = [{ 
            id: uuidv4(), 
            role: 'model', 
            text: template 
              ? `Image uploaded. I'll analyze it for the **${template}** style.` 
              : 'Image uploaded. Ready for your instructions!', 
            timestamp: Date.now() 
          }];

          const updatedProject: Project = {
              ...projectToUpdate,
              name: `Project ${projects.length}`,
              thumbnail: base64,
              timestamp: Date.now(),
              editLog: [{
                id: uuidv4(),
                timestamp: Date.now(),
                action: 'Initialized',
                details: template ? `Uploaded base image (${template})` : 'Uploaded base image'
            }, ...projectToUpdate.editLog],
            history: initialHistory,
            historyIndex: 0,
            messages: initialMessages
          };

          await saveProjectToDB(updatedProject);
          setProjects(prev => prev.map(p => p.id === projectId ? updatedProject : p));

          setCurrentImage(base64);
          setHistory(initialHistory);
          setHistoryIndex(0);
          setMessages(initialMessages);
      } else {
          // Case 3: Add to history of CURRENT project (Treat as an edit/replacement)
          setCurrentImage(base64);
          const { newHistory, newIndex } = addToHistory(base64, 'Replaced Image');

          const systemMsg: Message = {
            id: uuidv4(),
            role: 'system',
            text: template 
              ? `Base image replaced (Style: ${template})` 
              : 'Base image replaced with new upload',
            timestamp: Date.now()
          };
          const newMessages = [...messages, systemMsg];
          setMessages(newMessages);

          // Log update
          await updateProjectState(projectId, {
              thumbnail: base64,
              history: newHistory,
              historyIndex: newIndex,
              messages: newMessages
          }, {
              action: 'Upload',
              details: template ? `Replaced base image (${template})` : 'Replaced base image'
          });

          showToast("Image replaced successfully");
      }

      // --- AUTO ANALYZE LOGIC ---
      // If we just uploaded a fresh image (Case 1 or 2) and Auto-Analyze is ON
      if (isNewOrReset && autoAnalyzeEnabled && projectId) {
          handleAnalyzeImage(base64, projectId, template);
      }

    } catch (error) {
      console.error("Error reading file:", error);
      alert("Failed to read file. Please try again.");
    }
  };

  const handleSendMessage = useCallback(async (text: string, mode: 'edit' | 'chat') => {
    const activeProjectId = currentProjectIdRef.current;
    if (!activeProjectId) return;
    if (!text.trim()) return; // Don't send empty messages

    // For Edit Mode, we need an image. For Chat Mode, we don't necessarily need one, but it's often context.
    if (mode === 'edit' && !currentImage) return;

    const userMsg: Message = {
      id: uuidv4(),
      role: 'user',
      text: text,
      timestamp: Date.now()
    };

    // Optimistic UI update for messages
    const updatedMessages = [...messagesRef.current, userMsg];
    setMessages(updatedMessages);

    // Increment generation ID to identify this request
    const currentGenId = ++generationIdRef.current;
    setIsGenerating(true);

    // Capture the current region and dismiss the UI immediately
    const regionToUse = selectedRegion;
    if (mode === 'edit') {
        setSelectedRegion(null);
    }

    try {
      if (mode === 'edit' && currentImage) {
          // --- IMAGE EDITING FLOW ---
          // Pass the selected region if available (captured before dismissal)
          const newImageData = await editImageWithGemini(currentImage, text, regionToUse);

          // Check if cancelled or superseded
          if (currentGenId !== generationIdRef.current) {
            console.log("Generation canceled or superseded");
            return;
          }

          const newImageSrc = `data:image/png;base64,${newImageData}`;

          // Check if user switched projects while waiting
          if (activeProjectId !== currentProjectIdRef.current) {
            console.log("Project switched during generation, discarding result.");
            return;
          }

          setCurrentImage(newImageSrc);
          const { newHistory, newIndex } = addToHistory(newImageSrc, text);

          const botMsg: Message = {
            id: uuidv4(),
            role: 'model',
            text: `I've updated the thumbnail based on: "${text}". How does it look?`,
            timestamp: Date.now()
          };
          const finalMessages = [...updatedMessages, botMsg];
          setMessages(finalMessages);

          // Note: Region selection is already cleared above

          // Log update AND Persist History/Messages
          await updateProjectState(activeProjectId, {
              thumbnail: newImageSrc,
              history: newHistory,
              historyIndex: newIndex,
              messages: finalMessages
          }, {
              action: 'Edit',
              details: text
          });

      } else {
          // --- CHAT ONLY FLOW ---
          const responseText = await chatWithGemini(updatedMessages, text);

          if (currentGenId !== generationIdRef.current) return;

          const botMsg: Message = {
              id: uuidv4(),
              role: 'model',
              text: responseText,
              timestamp: Date.now()
          };
          const finalMessages = [...updatedMessages, botMsg];
          setMessages(finalMessages);

          // Persist Messages Only
          await updateProjectState(activeProjectId, {
              messages: finalMessages
          });
      }

    } catch (error: any) {
      // If cancelled, ignore error
      if (currentGenId !== generationIdRef.current) return;

      console.error("Gemini Error:", error);

      if (activeProjectId === currentProjectIdRef.current) {
        let errorMessage = "Sorry, I encountered an error. Please try again.";

        if (error.message?.includes('502') || error.message?.includes('Failed to fetch')) {
             errorMessage = "Network error: Unable to reach the AI service. This might be a temporary connection issue.";
        } else if (error.message?.includes('SAFETY')) {
             errorMessage = "The generation was blocked by safety filters. Please try a different prompt.";
        } else if (error.message?.includes('401')) {
             errorMessage = "Authentication error: Please check your API key configuration.";
        }

        const errorMsg: Message = {
            id: uuidv4(),
            role: 'model',
            text: errorMessage,
            timestamp: Date.now()
        };
        const finalMessages = [...updatedMessages, errorMsg];
        setMessages(finalMessages);

        // Save state even on error to persist the chat logs
        await updateProjectState(activeProjectId, {
            messages: finalMessages
        });
      }
    } finally {
      // Only turn off generating if this was the active request
      if (currentGenId === generationIdRef.current && activeProjectId === currentProjectIdRef.current) {
         setIsGenerating(false);
      }
    }
  }, [currentImage, selectedRegion]);

  const handleStopGeneration = useCallback(() => {
    // Increment ID to invalidate any pending requests
    generationIdRef.current++;
    setIsGenerating(false);
    setIsAnalyzing(false);

    // Add system message indicating cancellation
    const systemMsg: Message = {
        id: uuidv4(),
        role: 'system',
        text: 'Generation canceled',
        timestamp: Date.now()
    };

    setMessages(prev => {
        const newMessages = [...prev, systemMsg];
        // Persist the cancellation message
        if (currentProjectIdRef.current) {
             updateProjectState(currentProjectIdRef.current, { messages: newMessages });
        }
        return newMessages;
    });

    showToast("Generation canceled");
  }, []);

  const handleUndo = () => {
    if (historyIndex > 0 && currentProjectId) {
      const newIndex = historyIndex - 1;
      const prevItem = history[newIndex];
      const actionUndone = history[historyIndex].action;

      setHistoryIndex(newIndex);
      setCurrentImage(prevItem.thumbnail);
      // Clear region on undo to avoid confusion
      setSelectedRegion(null);

      // Visual feedback
      showVisualFeedback('undo', actionUndone);

      const systemMsg: Message = {
        id: uuidv4(),
        role: 'system',
        text: `Undid: ${actionUndone}`,
        timestamp: Date.now()
      };
      const newMessages = [...messages, systemMsg];
      setMessages(newMessages);

      // Log update and persist state
      updateProjectState(currentProjectId, {
          thumbnail: prevItem.thumbnail,
          historyIndex: newIndex, // Only need to update index, history array is same
          messages: newMessages
      }, {
          action: 'Undo',
          details: `Undid: ${actionUndone}`
      });

      showToast('Undo successful', <Undo2 size={16} className="text-zinc-400" />);
    }
  };

  const handleRedo = () => {
    if (historyIndex < history.length - 1 && currentProjectId) {
      const newIndex = historyIndex + 1;
      const nextItem = history[newIndex];
      const actionRedone = nextItem.action;

      setHistoryIndex(newIndex);
      setCurrentImage(nextItem.thumbnail);
      // Clear region on redo
      setSelectedRegion(null);

      // Visual feedback
      showVisualFeedback('redo', actionRedone);

      const systemMsg: Message = {
        id: uuidv4(),
        role: 'system',
        text: `Redid: ${actionRedone}`,
        timestamp: Date.now()
      };
      const newMessages = [...messages, systemMsg];
      setMessages(newMessages);

      // Log update and persist state
      updateProjectState(currentProjectId, {
          thumbnail: nextItem.thumbnail,
          historyIndex: newIndex,
          messages: newMessages
      }, {
          action: 'Redo',
          details: `Redid: ${actionRedone}`
      });

      showToast('Redo successful', <Redo2 size={16} className="text-zinc-400" />);
    }
  };

  const handleJumpToHistory = (index: number) => {
      if (index < 0 || index >= history.length || !currentProjectId) return;

      const targetItem = history[index];
      // Determine direction for visual feedback
      const direction = index < historyIndex ? 'undo' : 'redo';

      setHistoryIndex(index);
      setCurrentImage(targetItem.thumbnail);
      setSelectedRegion(null);

      showVisualFeedback(direction, targetItem.action);

      const systemMsg: Message = {
        id: uuidv4(),
        role: 'system',
        text: `Jumped to: ${targetItem.action}`,
        timestamp: Date.now()
      };
      const newMessages = [...messages, systemMsg];
      setMessages(newMessages);

      // Persist the jump
      updateProjectState(currentProjectId, {
          thumbnail: targetItem.thumbnail,
          historyIndex: index,
          messages: newMessages
      }, {
          action: 'History Jump',
          details: `Jumped to state: ${targetItem.action}`
      });
  };

  const handleDownload = (blob: Blob, fileName: string) => {
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(link.href);
    showToast('Export successful');
  };

  // --- PROJECT MANAGEMENT ---

  const handleNewProject = async (folderId?: string) => {
    const newId = uuidv4();
    const newProject: Project = {
        id: newId,
        name: "Untitled Project",
        thumbnail: PLACEHOLDER_THUMBNAIL,
        timestamp: Date.now(),
        folderId: folderId, // Assign to folder if created within one
        editLog: [{
            id: uuidv4(),
            timestamp: Date.now(),
            action: 'Created',
            details: 'New empty project'
        }],
        history: [],
        historyIndex: -1,
        messages: []
    };

    try {
        await saveProjectToDB(newProject);
        setProjects(prev => [newProject, ...prev]);
        setCurrentProjectId(newId);

        // Reset Workspace Cleanly
        setCurrentImage(null);
        setHistory([]);
        setHistoryIndex(-1);
        setMessages([]); 
        setIsGenerating(false);
        setIsAnalyzing(false);
        setSelectedRegion(null);
        showToast("New project created");
    } catch (e) {
        console.error("Failed to create new project", e);
    }
  };

  const handleLoadProject = (project: Project) => {
    if (project.id === currentProjectId) return;
    setCurrentProjectId(project.id);
    setIsGenerating(false); // Reset any lingering generation state
    setIsAnalyzing(false);
    setSelectedRegion(null);
    generationIdRef.current++; // Invalidate any pending requests for the old project

    // Robust check for placeholder or missing thumbnail
    if (!project.thumbnail || project.thumbnail === PLACEHOLDER_THUMBNAIL) {
        setCurrentImage(null);
        setHistory([]);
        setHistoryIndex(-1);
        setMessages([]);
    } else {
        setCurrentImage(project.thumbnail);

        // Restore History from DB if available, else init
        if (project.history && project.history.length > 0) {
            setHistory(project.history);
            setHistoryIndex(project.historyIndex ?? project.history.length - 1);
        } else {
            // Fallback for old projects without history or corrupt data
            const fallbackHistory = [{ 
                id: uuidv4(), 
                thumbnail: project.thumbnail, 
                action: 'Loaded Project', 
                timestamp: Date.now() 
            }];
            setHistory(fallbackHistory);
            setHistoryIndex(0);
        }

        // Restore Messages from DB if available, else init
        if (project.messages && project.messages.length > 0) {
            setMessages(project.messages);
        } else {
            // Fallback for old projects
            setMessages([{
                id: uuidv4(),
                role: 'system',
                text: `Loaded project "${project.name}"`,
                timestamp: Date.now(),
            }]);
        }
    }
  };

  const handleDeleteProject = async (id: string) => {
    try {
      await deleteProjectFromDB(id);
      setProjects(prev => prev.filter(p => p.id !== id));
      if (currentProjectId === id) {
        setCurrentImage(null);
        setHistory([]);
        setHistoryIndex(-1);
        setMessages([]);
        setCurrentProjectId(null);
        setSelectedRegion(null);
      }
      showToast("Project deleted");
    } catch (e) {
      console.error("Failed to delete project", e);
    }
  };

  const handleRenameProject = async (id: string, newName: string) => {
    setProjects(prev => prev.map(p => {
      if (p.id === id) {
        const updated = { ...p, name: newName };
        saveProjectToDB(updated).catch(console.error);
        return updated;
      }
      return p;
    }));
  };

  const handleMoveProject = async (projectId: string, folderId: string | undefined) => {
      // Optimistic update
      setProjects(prev => prev.map(p => {
          if (p.id === projectId) {
              return { ...p, folderId: folderId };
          }
          return p;
      }));

      // DB Update
      const project = projects.find(p => p.id === projectId);
      if (project) {
          const updated = { ...project, folderId: folderId };
          await saveProjectToDB(updated);
          showToast(`Moved to ${folderId ? 'folder' : 'projects'}`);
      }
  };

  // --- FOLDER MANAGEMENT ---

  const handleCreateFolder = async () => {
    const newFolder: Folder = {
        id: uuidv4(),
        name: "New Folder",
        timestamp: Date.now()
    };

    try {
        await saveFolderToDB(newFolder);
        setFolders(prev => [newFolder, ...prev]);
        showToast("Folder created");
    } catch (e) {
        console.error("Failed to create folder", e);
    }
  };

  const handleDeleteFolder = async (id: string) => {
      try {
          await deleteFolderFromDB(id);
          setFolders(prev => prev.filter(f => f.id !== id));

          // Move projects in this folder to Root (undefined)
          const projectsToUpdate = projects.filter(p => p.folderId === id);
          if (projectsToUpdate.length > 0) {
              const updatedProjects = projectsToUpdate.map(p => ({ ...p, folderId: undefined }));

              // Update state
              setProjects(prev => prev.map(p => {
                  const updated = updatedProjects.find(up => up.id === p.id);
                  return updated || p;
              }));

              // Update DB
              updatedProjects.forEach(p => saveProjectToDB(p));
          }

          showToast("Folder deleted");
      } catch (e) {
          console.error("Failed to delete folder", e);
      }
  };

  const handleRenameFolder = async (id: string, newName: string) => {
      setFolders(prev => prev.map(f => {
          if (f.id === id) {
              const updated = { ...f, name: newName };
              saveFolderToDB(updated).catch(console.error);
              return updated;
          }
          return f;
      }));
  };

  // --- Render ---

  if (isProjectsLoading) {
    return (
      <div className="flex h-screen w-full items-center justify-center bg-black text-white">
        <div className="flex flex-col items-center gap-4">
          <Loader2 className="w-8 h-8 animate-spin text-brand-500" />
          <p className="text-zinc-500 font-light">Loading thumbio...</p>
        </div>
      </div>
    );
  }

  // Get current and next actions for tooltips
  const undoAction = historyIndex > 0 ? history[historyIndex].action : null;
  const redoAction = historyIndex < history.length - 1 ? history[historyIndex + 1].action : null;

  return (
    <div className="flex flex-col h-screen w-screen bg-black text-white font-sans overflow-hidden selection:bg-brand-500/30">
        {/* Toast Notification */}
        {toast && (
          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-[60] animate-in fade-in slide-in-from-bottom-4 duration-300 pointer-events-none">
            <div className="bg-[#1C1C1E] border border-white/10 shadow-2xl shadow-black/50 text-white px-4 py-2.5 rounded-full flex items-center gap-3 ring-1 ring-white/5">
               {toast.icon}
               <span className="text-sm font-medium">{toast.message}</span>
            </div>
          </div>
        )}

        {/* Header */}
        <header className="h-14 shrink-0 bg-[#09090b] border-b border-white/10 flex items-center px-4 justify-between z-50">
            {/* Left: Brand */}
            <div className="flex items-center gap-3 select-none">
                <div className="bg-gradient-to-br from-brand-600 to-brand-700 p-1.5 rounded-lg shadow-lg shadow-brand-900/20 ring-1 ring-white/10">
                    <Zap className="w-4 h-4 text-white fill-white" />
                </div>
                <h1 className="font-semibold text-lg tracking-tight text-white/90">thumbio</h1>
            </div>

            {/* Right: Profile */}
            <div className="flex items-center gap-4">
               <div className="relative">
                  <button 
                    onClick={() => setShowProfileMenu(!showProfileMenu)}
                    className="flex items-center gap-2 pl-2 pr-1 py-1 rounded-full hover:bg-white/5 transition-colors group"
                  >
                     <img 
                       src="https://api.dicebear.com/9.x/avataaars/svg?seed=Felix" 
                       alt="Profile" 
                       className="w-7 h-7 rounded-full bg-zinc-800 ring-2 ring-black group-hover:ring-white/10 transition-all"
                     />
                     <ChevronDown className={`w-3.5 h-3.5 text-zinc-500 transition-transform duration-200 ${showProfileMenu ? 'rotate-180' : ''}`} />
                  </button>

                  {showProfileMenu && (
                    <>
                      <div className="fixed inset-0 z-40" onClick={() => setShowProfileMenu(false)} />
                      <div className="absolute right-0 top-full mt-2 w-56 bg-[#1C1C1E] border border-white/10 rounded-xl shadow-2xl py-1 z-50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                          <div className="px-4 py-3 border-b border-white/5">
                             <p className="text-sm font-medium text-white">Guest User</p>
                             <p className="text-xs text-zinc-500 mt-0.5">guest@thumbio.ai</p>
                          </div>
                          <div className="p-1">
                            <button className="w-full text-left px-3 py-2 text-sm text-zinc-300 hover:bg-white/5 hover:text-white rounded-lg flex items-center gap-2 transition-colors">
                               <Settings className="w-4 h-4" /> Settings
                            </button>
                             <button className="w-full text-left px-3 py-2 text-sm text-zinc-300 hover:bg-white/5 hover:text-white rounded-lg flex items-center gap-2 transition-colors">
                               <UserIcon className="w-4 h-4" /> Profile
                            </button>
                          </div>
                          <div className="border-t border-white/5 p-1">
                            <button className="w-full text-left px-3 py-2 text-sm text-red-400 hover:bg-red-500/10 rounded-lg flex items-center gap-2 transition-colors">
                               <LogOut className="w-4 h-4" /> Sign out
                            </button>
                          </div>
                      </div>
                    </>
                  )}
               </div>
            </div>
        </header>

        {/* Main Content */}
        <div className="flex-1 flex flex-col min-h-0">
            <div className="flex-1 flex flex-row min-h-0">

                {/* Editor Area (U) */}
                <main className="flex-1 relative bg-[#050505] min-w-0 overflow-hidden">
                    <ImageArea 
                        currentImage={currentImage}
                        onImageUpload={handleImageUpload}
                        onSendEdit={(text) => handleSendMessage(text, 'edit')}
                        isGenerating={isGenerating}
                        onUndo={handleUndo}
                        onRedo={handleRedo}
                        canUndo={historyIndex > 0}
                        canRedo={historyIndex < history.length - 1}
                        onDownload={handleDownload}
                        history={history}
                        historyIndex={historyIndex}
                        onJumpToHistory={handleJumpToHistory}
                        feedbackAction={visualFeedback}
                        undoLabel={undoAction}
                        redoLabel={redoAction}
                        onAnalyze={() => handleAnalyzeImage()}
                        autoAnalyzeEnabled={autoAnalyzeEnabled}
                        onToggleAutoAnalyze={() => setAutoAnalyzeEnabled(prev => !prev)}
                        key={currentProjectId || 'empty'}
                        isAnalyzing={isAnalyzing}
                        selectedRegion={selectedRegion}
                        onRegionChange={setSelectedRegion}
                    />
                    {isResizing && <div className="absolute inset-0 z-50 cursor-col-resize" />}
                </main>

                {/* Drag Handle */}
                <div
                    className={`w-1.5 -ml-0.5 relative z-40 cursor-col-resize hover:bg-brand-500 transition-colors flex items-center justify-center group ${isResizing ? 'bg-brand-500' : 'bg-[#09090b] border-l border-white/10'}`}
                    onMouseDown={startResizing}
                >
                     <div className={`h-8 w-1 rounded-full transition-colors ${isResizing ? 'bg-white' : 'bg-white/20 group-hover:bg-white/50'}`} />
                </div>

                {/* Chat Sidebar (C) */}
                <aside 
                    style={{ width: sidebarWidth }} 
                    className="shrink-0 bg-[#09090b] flex flex-col z-20 transition-[width] duration-0 ease-linear"
                >
                    <ChatSidebar 
                        messages={messages}
                        onSendMessage={handleSendMessage}
                        onStop={handleStopGeneration}
                        isGenerating={isGenerating}
                        hasImage={!!currentImage}
                    />
                </aside>
            </div>

            {/* Projects Panel (P) */}
            <section className="h-auto shrink-0 border-t border-white/10 bg-[#09090b] z-30">
                <ProjectsPanel 
                    projects={projects}
                    folders={folders}
                    onLoadProject={handleLoadProject}
                    onDeleteProject={handleDeleteProject}
                    onRenameProject={handleRenameProject}
                    onNewProject={handleNewProject}
                    onMoveProject={handleMoveProject}
                    onCreateFolder={handleCreateFolder}
                    onDeleteFolder={handleDeleteFolder}
                    onRenameFolder={handleRenameFolder}
                    currentProjectId={currentProjectId || undefined}
                />
            </section>
        </div>
    </div>
  );
};

export default App;

import React, { useCallback, useState, useEffect, useRef } from 'react';
import { Upload, Image as ImageIcon, Sparkles, Undo2, Redo2, Download, X, ZoomIn, History, Check, Settings, ChevronDown, FileType, Gauge, Scan, MousePointer2, Zap, Film, Smartphone, Gamepad2, Globe, Palette, LayoutTemplate, Send } from 'lucide-react';
import { HistoryItem, Region } from '../types';
import MiniGame from './MiniGame';
import EditingAnimation from './EditingAnimation';

interface ImageAreaProps {
  currentImage: string | null;
  onImageUpload: (file: File, template?: string) => void;
  onSendEdit?: (text: string) => void;
  isGenerating: boolean;
  onUndo: () => void;
  onRedo: () => void;
  canUndo: boolean;
  canRedo: boolean;
  onDownload: (blob: Blob, fileName: string) => void;
  // History Props
  history: HistoryItem[];
  historyIndex: number;
  onJumpToHistory: (index: number) => void;
  // Feedback Props
  feedbackAction?: { type: 'undo' | 'redo', label: string } | null;
  undoLabel?: string;
  redoLabel?: string;
  // Analysis
  onAnalyze: () => void;
  autoAnalyzeEnabled?: boolean;
  onToggleAutoAnalyze?: () => void;
  isAnalyzing?: boolean;
  // Region Editing
  selectedRegion?: Region | null;
  onRegionChange?: (region: Region | null) => void;
}

const TEMPLATES = [
  { id: 'Mr Beast Style', icon: Zap, label: 'Mr Beast', desc: 'Viral, Shocked, Vibrant', color: 'text-yellow-400', border: 'border-yellow-500/50', bg: 'bg-yellow-500/10' },
  { id: 'Cinematic Vlog', icon: Film, label: 'Cinematic', desc: 'Film Look, Moody', color: 'text-cyan-400', border: 'border-cyan-500/50', bg: 'bg-cyan-500/10' },
  { id: 'MKBHD Tech', icon: Smartphone, label: 'Tech Review', desc: 'Clean, Matte, 8K', color: 'text-zinc-100', border: 'border-zinc-300/50', bg: 'bg-zinc-500/10' },
  { id: 'Epic Gaming', icon: Gamepad2, label: 'Gaming', desc: 'Action, Effects, Red', color: 'text-purple-500', border: 'border-purple-500/50', bg: 'bg-purple-500/10' },
  { id: 'Documentary', icon: Globe, label: 'Documentary', desc: 'Gritty, Realistic', color: 'text-emerald-400', border: 'border-emerald-500/50', bg: 'bg-emerald-500/10' },
  { id: 'Brain Storm', icon: Palette, label: 'Creative', desc: 'Abstract, Artistic', color: 'text-pink-400', border: 'border-pink-500/50', bg: 'bg-pink-500/10' },
];

const ImageArea: React.FC<ImageAreaProps> = ({ 
  currentImage, 
  onImageUpload, 
  onSendEdit,
  isGenerating,
  onUndo,
  onRedo,
  canUndo,
  canRedo,
  onDownload,
  history,
  historyIndex,
  onJumpToHistory,
  feedbackAction,
  undoLabel,
  redoLabel,
  onAnalyze,
  autoAnalyzeEnabled = false,
  onToggleAutoAnalyze,
  isAnalyzing = false,
  selectedRegion,
  onRegionChange
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [showLightbox, setShowLightbox] = useState(false);
  const [showHistoryDropdown, setShowHistoryDropdown] = useState(false);
  const [showExportMenu, setShowExportMenu] = useState(false);
  const [showTemplates, setShowTemplates] = useState(false);

  // Selection Tool State
  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [isDrawing, setIsDrawing] = useState(false);
  const [dragStart, setDragStart] = useState<{x: number, y: number} | null>(null);
  const [regionPrompt, setRegionPrompt] = useState("");

  // Template State
  const [selectedTemplate, setSelectedTemplate] = useState<string | null>(null);

  // Export State
  const [exportFormat, setExportFormat] = useState<'png' | 'jpeg' | 'webp'>('png');
  const [exportQuality, setExportQuality] = useState(0.9);
  const [estimatedSize, setEstimatedSize] = useState<string | null>(null);
  const [isCalculatingSize, setIsCalculatingSize] = useState(false);

  const historyDropdownRef = useRef<HTMLDivElement>(null);
  const exportMenuRef = useRef<HTMLDivElement>(null);
  const sizeCalculationTimeoutRef = useRef<number | null>(null);
  const imageRef = useRef<HTMLImageElement>(null);

  // Reset lightbox when image changes
  useEffect(() => {
    setShowLightbox(false);
  }, [currentImage]);

  // Auto-exit selection mode when generation starts
  useEffect(() => {
    if (isGenerating) {
        setIsSelectionMode(false);
    }
  }, [isGenerating]);

  // Clear region prompt when selection clears
  useEffect(() => {
    if (!selectedRegion) {
        setRegionPrompt("");
    }
  }, [selectedRegion]);

  // Force cursor style during drawing for better UX
  useEffect(() => {
    if (isDrawing) {
        document.body.style.cursor = 'crosshair';
    } else {
        document.body.style.cursor = '';
    }
    return () => { document.body.style.cursor = ''; };
  }, [isDrawing]);

  // Click outside handlers
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (historyDropdownRef.current && !historyDropdownRef.current.contains(event.target as Node)) {
            setShowHistoryDropdown(false);
        }
        if (exportMenuRef.current && !exportMenuRef.current.contains(event.target as Node)) {
            setShowExportMenu(false);
        }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- Drag and Drop for Upload ---
  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    if (!isSelectionMode) {
       setIsDragging(true);
    }
  }, [isSelectionMode]);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);

    if (isSelectionMode) return;

    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      const file = e.dataTransfer.files[0];
      if (file.type.startsWith('image/')) {
        onImageUpload(file, selectedTemplate || undefined);
      }
    }
  }, [onImageUpload, isSelectionMode, selectedTemplate]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      onImageUpload(e.target.files[0], selectedTemplate || undefined);
    }
  };

  // --- Region Selection Logic ---

  const getNormalizedCoordinates = useCallback((e: React.MouseEvent | MouseEvent) => {
      const img = imageRef.current;
      if (!img) return null;

      const rect = img.getBoundingClientRect();
      const imageRatio = img.naturalWidth / img.naturalHeight;
      const containerRatio = rect.width / rect.height;

      let renderWidth = rect.width;
      let renderHeight = rect.height;
      let offsetX = 0;
      let offsetY = 0;

      // Calculate actual rendered image dimensions within the object-contain element
      if (containerRatio > imageRatio) {
          // Pillarboxed (bars on sides)
          renderWidth = rect.height * imageRatio;
          offsetX = (rect.width - renderWidth) / 2;
      } else {
          // Letterboxed (bars on top/bottom)
          renderHeight = rect.width / imageRatio;
          offsetY = (rect.height - renderHeight) / 2;
      }

      // Calculate position relative to the actual image content
      const clickX = e.clientX - rect.left;
      const clickY = e.clientY - rect.top;

      let x = (clickX - offsetX) / renderWidth;
      let y = (clickY - offsetY) / renderHeight;

      // Clamp values
      x = Math.max(0, Math.min(1, x));
      y = Math.max(0, Math.min(1, y));

      return { x, y };
  }, []);

  // Use global window listeners for dragging to allow dragging outside the image area
  useEffect(() => {
    if (!isDrawing || !dragStart) return;

    const handleWindowMouseMove = (e: MouseEvent) => {
        if (!onRegionChange) return;
        e.preventDefault(); 

        const coords = getNormalizedCoordinates(e);
        if (coords) {
            const x = Math.min(dragStart.x, coords.x);
            const y = Math.min(dragStart.y, coords.y);
            const width = Math.abs(coords.x - dragStart.x);
            const height = Math.abs(coords.y - dragStart.y);

            onRegionChange({ x, y, width, height });
        }
    };

    const handleWindowMouseUp = () => {
        setIsDrawing(false);
        setDragStart(null);
    };

    window.addEventListener('mousemove', handleWindowMouseMove);
    window.addEventListener('mouseup', handleWindowMouseUp);

    return () => {
        window.removeEventListener('mousemove', handleWindowMouseMove);
        window.removeEventListener('mouseup', handleWindowMouseUp);
    };
  }, [isDrawing, dragStart, onRegionChange, getNormalizedCoordinates]);

  const handleMouseDown = (e: React.MouseEvent) => {
      if (!isSelectionMode || !currentImage) return;
      e.preventDefault();
      e.stopPropagation(); // Prevent propagation to avoid conflicts

      const coords = getNormalizedCoordinates(e);
      if (coords) {
          setIsDrawing(true);
          setDragStart(coords);
          // Start with zero size
          if (onRegionChange) {
              onRegionChange({ x: coords.x, y: coords.y, width: 0, height: 0 });
          }
      }
  };

  // Resize handler
  const handleResizeStart = (e: React.MouseEvent, corner: 'tl' | 'tr' | 'bl' | 'br') => {
      e.preventDefault();
      e.stopPropagation();

      if (!selectedRegion) return;

      const { x, y, width, height } = selectedRegion;
      let anchorX = 0;
      let anchorY = 0;

      // Set the anchor to the opposite corner
      if (corner === 'tl') { anchorX = x + width; anchorY = y + height; }
      else if (corner === 'tr') { anchorX = x; anchorY = y + height; }
      else if (corner === 'bl') { anchorX = x + width; anchorY = y; }
      else if (corner === 'br') { anchorX = x; anchorY = y; }

      setDragStart({ x: anchorX, y: anchorY });
      setIsDrawing(true);
  };

  // Clear selection if mode is turned off
  useEffect(() => {
      if (!isSelectionMode && selectedRegion && onRegionChange) {
          onRegionChange(null);
      }
  }, [isSelectionMode]);

  const handleRegionPromptSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      if (regionPrompt.trim() && onSendEdit) {
          setIsSelectionMode(false); // Dismiss mode immediately for snappy feedback
          onSendEdit(regionPrompt.trim());
          setRegionPrompt("");
      }
  };

  // --- Export Logic ---

  const formatBytes = (bytes: number, decimals = 1) => {
      if (bytes === 0) return '0 Bytes';
      const k = 1024;
      const dm = decimals < 0 ? 0 : decimals;
      const sizes = ['Bytes', 'KB', 'MB', 'GB'];
      const i = Math.floor(Math.log(bytes) / Math.log(k));
      return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
  };

  const calculateSize = useCallback(() => {
      if (!currentImage) return;
      setIsCalculatingSize(true);

      const img = new Image();
      img.src = currentImage;
      img.onload = () => {
          const canvas = document.createElement('canvas');
          canvas.width = img.width;
          canvas.height = img.height;
          const ctx = canvas.getContext('2d');
          if (ctx) {
              ctx.drawImage(img, 0, 0);
              const mimeType = `image/${exportFormat}`;
              canvas.toBlob((blob) => {
                  if (blob) {
                      setEstimatedSize(formatBytes(blob.size));
                  }
                  setIsCalculatingSize(false);
              }, mimeType, exportQuality);
          }
      };
  }, [currentImage, exportFormat, exportQuality]);

  // Debounced size calculation
  useEffect(() => {
      if (showExportMenu) {
          if (sizeCalculationTimeoutRef.current) {
              window.clearTimeout(sizeCalculationTimeoutRef.current);
          }
          sizeCalculationTimeoutRef.current = window.setTimeout(calculateSize, 200);
      }
  }, [showExportMenu, exportFormat, exportQuality, calculateSize]);

  const handleExportClick = () => {
      if (!currentImage) return;

      const img = new Image();
      img.src = currentImage;
      img.onload = () => {
          const canvas = document.createElement('canvas');
          canvas.width = img.width;
          canvas.height = img.height;
          const ctx = canvas.getContext('2d');
          if (ctx) {
              ctx.drawImage(img, 0, 0);
              const mimeType = `image/${exportFormat}`;
              canvas.toBlob((blob) => {
                  if (blob) {
                      const randomNumber = Math.floor(1000 + Math.random() * 9000);
                      const fileName = `thumbio-${randomNumber}.${exportFormat}`;
                      onDownload(blob, fileName);
                      setShowExportMenu(false);
                  }
              }, mimeType, exportQuality);
          }
      };
  };

  return (
    <div 
      className={`relative flex-1 h-full flex flex-col transition-colors duration-500 ease-out ${
        isDragging ? 'bg-brand-900/10' : 'bg-[#0D0D0D]'
      }`}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      {/* Lightbox / Popup Window */}
      {showLightbox && currentImage && (
        <div 
          className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-md flex items-center justify-center p-4 sm:p-8 animate-in fade-in duration-200"
          onClick={() => setShowLightbox(false)}
        >
            <div className="absolute top-4 right-4 z-50">
                <button 
                  onClick={() => setShowLightbox(false)}
                  className="p-3 bg-white/10 hover:bg-white/20 rounded-full text-white transition-all hover:rotate-90"
                >
                    <X size={24} />
                </button>
            </div>
            <img 
              src={currentImage} 
              alt="Full view"
              className="max-w-full max-h-full object-contain shadow-2xl rounded-sm cursor-zoom-out select-none"
              onClick={(e) => e.stopPropagation()} 
            />
            <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-black/50 backdrop-blur-md text-white/70 px-4 py-2 rounded-full text-xs font-medium border border-white/10 pointer-events-none">
                Viewing in popup mode
            </div>
        </div>
      )}

      {/* Toolbar - Glassmorphism Floating Bar */}
      {currentImage && (
        <div className="absolute top-6 left-0 right-0 z-30 flex justify-center pointer-events-none px-4 animate-in fade-in slide-in-from-top-4 duration-500">
          <div className="bg-[#1C1C1E]/80 backdrop-blur-xl border border-white/10 p-1.5 rounded-2xl flex items-center gap-1 shadow-2xl shadow-black/50 pointer-events-auto">

             {/* Selection Tool */}
             <div className="border-r border-white/10 pr-1 mr-1">
                 <button
                    onClick={() => setIsSelectionMode(!isSelectionMode)}
                    className={`p-2.5 rounded-xl transition-all active:scale-95 flex items-center gap-2 ${
                        isSelectionMode ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/30' : 'text-zinc-300 hover:bg-white/10 hover:text-white'
                    }`}
                    title="Selection Mode"
                 >
                     <Scan size={18} strokeWidth={isSelectionMode ? 2.5 : 2} />
                 </button>
             </div>

             {/* Suggestions Toggle */}
             <div className="border-r border-white/10 pr-1 mr-1">
                <button
                    onClick={onAnalyze}
                    disabled={isGenerating}
                    className="p-2.5 rounded-xl transition-all active:scale-95 flex items-center gap-2 text-brand-400 hover:bg-brand-500/10 hover:text-brand-300 disabled:opacity-50"
                    title="Get AI Suggestions"
                >
                    <Sparkles size={18} strokeWidth={2} className="fill-brand-500/20" />
                </button>
             </div>

             {/* Undo/Redo Group */}
             <div className="flex items-center gap-0.5 border-r border-white/10 pr-1 mr-1">
                <div className="group relative">
                    <button 
                    onClick={onUndo}
                    disabled={!canUndo || isGenerating}
                    className="p-2.5 hover:bg-white/10 rounded-xl text-zinc-300 hover:text-white disabled:opacity-30 disabled:cursor-not-allowed transition-all active:scale-95"
                    >
                    <Undo2 size={18} strokeWidth={2} />
                    </button>
                    {canUndo && undoLabel && (
                        <div className="absolute top-full mt-3 left-1/2 -translate-x-1/2 px-2.5 py-1.5 bg-[#27272a] text-white text-[10px] font-medium rounded-lg whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none border border-white/10 shadow-xl z-50">
                            Undo: {undoLabel}
                            <div className="absolute -top-1 left-1/2 -translate-x-1/2 w-2 h-2 bg-[#27272a] border-t border-l border-white/10 rotate-45"></div>
                        </div>
                    )}
                </div>

                <div className="group relative">
                    <button 
                    onClick={onRedo}
                    disabled={!canRedo || isGenerating}
                    className="p-2.5 hover:bg-white/10 rounded-xl text-zinc-300 hover:text-white disabled:opacity-30 disabled:cursor-not-allowed transition-all active:scale-95"
                    >
                    <Redo2 size={18} strokeWidth={2} />
                    </button>
                    {canRedo && redoLabel && (
                        <div className="absolute top-full mt-3 left-1/2 -translate-x-1/2 px-2.5 py-1.5 bg-[#27272a] text-white text-[10px] font-medium rounded-lg whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none border border-white/10 shadow-xl z-50">
                            Redo: {redoLabel}
                            <div className="absolute -top-1 left-1/2 -translate-x-1/2 w-2 h-2 bg-[#27272a] border-t border-l border-white/10 rotate-45"></div>
                        </div>
                    )}
                </div>
             </div>

             {/* History Dropdown */}
             <div className="relative mr-1 border-r border-white/10 pr-1" ref={historyDropdownRef}>
                <button
                    onClick={() => setShowHistoryDropdown(!showHistoryDropdown)}
                    className={`p-2.5 rounded-xl transition-all active:scale-95 flex items-center gap-2 ${
                        showHistoryDropdown ? 'bg-white/10 text-white' : 'text-zinc-300 hover:bg-white/10 hover:text-white'
                    }`}
                >
                    <History size={18} strokeWidth={2} />
                </button>

                {showHistoryDropdown && (
                    <div className="absolute top-full mt-3 left-1/2 -translate-x-1/2 w-64 bg-[#1C1C1E] border border-white/10 rounded-xl shadow-2xl overflow-hidden z-50 animate-in fade-in zoom-in-95 duration-150 origin-top">
                        <div className="px-3 py-2 bg-white/5 border-b border-white/5 flex justify-between items-center">
                            <span className="text-[10px] font-bold uppercase text-zinc-400 tracking-wider">Timeline</span>
                            <span className="text-[10px] text-zinc-600">{history.length} states</span>
                        </div>
                        <div className="max-h-60 overflow-y-auto scrollbar-thin scrollbar-thumb-zinc-700 p-1">
                            {history.slice().reverse().map((item, reverseIndex) => {
                                const actualIndex = history.length - 1 - reverseIndex;
                                const isCurrent = actualIndex === historyIndex;
                                const isFuture = actualIndex > historyIndex;

                                return (
                                    <button
                                        key={item.id}
                                        onClick={() => {
                                            onJumpToHistory(actualIndex);
                                            setShowHistoryDropdown(false);
                                        }}
                                        className={`w-full text-left px-3 py-2 rounded-lg text-xs flex items-center gap-3 transition-colors ${
                                            isCurrent 
                                                ? 'bg-brand-500/10 text-brand-400 border border-brand-500/20' 
                                                : isFuture
                                                    ? 'text-zinc-500 hover:bg-white/5'
                                                    : 'text-zinc-300 hover:bg-white/5'
                                        }`}
                                    >
                                        <div className={`w-1.5 h-1.5 rounded-full shrink-0 ${
                                            isCurrent ? 'bg-brand-500' : isFuture ? 'bg-zinc-700' : 'bg-zinc-500'
                                        }`} />
                                        <div className="flex-1 min-w-0">
                                            <p className={`truncate font-medium ${isFuture && 'line-through opacity-50'}`}>
                                                {item.action}
                                            </p>
                                            <p className="text-[9px] opacity-50">
                                                {new Date(item.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit', second:'2-digit'})}
                                            </p>
                                        </div>
                                        {isCurrent && <Check size={12} className="text-brand-500" />}
                                    </button>
                                );
                            })}
                        </div>
                        <div className="absolute -top-1 left-1/2 -translate-x-1/2 w-3 h-3 bg-[#1C1C1E] border-t border-l border-white/10 rotate-45"></div>
                    </div>
                )}
             </div>

             {/* Export Dropdown */}
             <div className="relative" ref={exportMenuRef}>
                 <button
                    onClick={() => setShowExportMenu(!showExportMenu)}
                    disabled={isGenerating}
                    className="flex items-center gap-2 px-4 py-2 bg-emerald-500 hover:bg-emerald-400 text-white rounded-xl transition-all font-semibold text-sm disabled:opacity-50 active:scale-95 shadow-lg shadow-emerald-900/20"
                 >
                    <Download size={16} strokeWidth={2.5} />
                    <span>Download</span>
                    <ChevronDown size={14} className={`transition-transform duration-200 ${showExportMenu ? 'rotate-180' : ''}`} />
                 </button>

                 {showExportMenu && (
                     <div className="absolute top-full mt-3 right-0 w-72 bg-[#1C1C1E] border border-white/10 rounded-xl shadow-2xl p-4 z-50 animate-in fade-in zoom-in-95 duration-150 origin-top-right">
                         <h3 className="text-xs font-bold uppercase text-zinc-400 mb-4 tracking-wider">Export Settings</h3>

                         <div className="space-y-4">
                             {/* Format Selection */}
                             <div className="space-y-2">
                                 <label className="text-xs text-zinc-300 flex items-center gap-2">
                                     <FileType size={12} /> Format
                                 </label>
                                 <div className="grid grid-cols-3 gap-2">
                                     {(['png', 'jpeg', 'webp'] as const).map(fmt => (
                                         <button
                                            key={fmt}
                                            onClick={() => setExportFormat(fmt)}
                                            className={`
                                                px-2 py-1.5 text-xs font-medium rounded-lg border transition-all uppercase
                                                ${exportFormat === fmt 
                                                    ? 'bg-emerald-500/10 border-emerald-500/50 text-emerald-400' 
                                                    : 'bg-white/5 border-white/5 text-zinc-400 hover:bg-white/10'
                                                }
                                            `}
                                         >
                                             {fmt === 'jpeg' ? 'JPG' : fmt}
                                         </button>
                                     ))}
                                 </div>
                             </div>

                             {/* Quality Slider (for JPG/WEBP) */}
                             {exportFormat !== 'png' ? (
                                 <div className="space-y-2">
                                     <div className="flex justify-between items-center text-xs text-zinc-300">
                                         <span className="flex items-center gap-2"><Gauge size={12} /> Quality</span>
                                         <span className="text-emerald-400 font-medium">{Math.round(exportQuality * 100)}%</span>
                                     </div>
                                     <input 
                                         type="range" 
                                         min="0.1" 
                                         max="1.0" 
                                         step="0.05"
                                         value={exportQuality}
                                         onChange={(e) => setExportQuality(parseFloat(e.target.value))}
                                         className="w-full h-1 bg-white/10 rounded-lg appearance-none cursor-pointer accent-emerald-500"
                                     />
                                 </div>
                             ) : (
                                 /* Lossless UI for PNG */
                                 <div className="space-y-2">
                                     <div className="flex justify-between items-center text-xs text-zinc-300">
                                         <span className="flex items-center gap-2"><Gauge size={12} /> Quality</span>
                                         <span className="text-emerald-400 font-medium">Lossless</span>
                                     </div>
                                     <div className="w-full h-8 bg-emerald-500/10 border border-emerald-500/20 rounded-lg flex items-center justify-center">
                                         <span className="text-[10px] font-medium text-emerald-400 tracking-wide uppercase flex items-center gap-1.5">
                                             <Check size={10} strokeWidth={3} /> Maximum Quality
                                         </span>
                                     </div>
                                 </div>
                             )}

                             {/* Size Estimation */}
                             <div className="bg-black/40 rounded-lg p-3 border border-white/5 flex justify-between items-center">
                                 <span className="text-xs text-zinc-500">Est. Size</span>
                                 <span className="text-xs font-mono text-zinc-300">
                                     {isCalculatingSize ? <span className="animate-pulse">...</span> : estimatedSize || '-'}
                                 </span>
                             </div>

                             {/* Download Button */}
                             <button
                                 onClick={handleExportClick}
                                 className="w-full py-2.5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-lg text-sm font-semibold shadow-lg shadow-emerald-900/20 transition-all active:scale-95"
                             >
                                 Save as .{exportFormat === 'jpeg' ? 'jpg' : exportFormat}
                             </button>
                         </div>
                         <div className="absolute -top-1 right-8 w-3 h-3 bg-[#1C1C1E] border-t border-l border-white/10 rotate-45"></div>
                     </div>
                 )}
             </div>
          </div>
        </div>
      )}

      {/* Main Content Area */}
      <div className="flex-1 flex items-center justify-center p-6 lg:p-12 overflow-hidden">
        {currentImage ? (
          <div className="relative w-full max-w-full lg:max-w-5xl aspect-video rounded-3xl shadow-2xl ring-1 ring-white/10 group bg-black overflow-hidden min-h-[200px]">

            {/* Blurred Background Layer for 16:9 Fill */}
            <div className="absolute inset-0 z-0">
                <img 
                    src={currentImage} 
                    alt="Background" 
                    className="w-full h-full object-cover blur-3xl scale-110 opacity-40 brightness-50"
                />
                <div className="absolute inset-0 bg-black/20" />
            </div>

            {/* Main Image Container */}
            <div 
                className={`relative w-full h-full group/image ${isSelectionMode ? 'cursor-crosshair' : ''}`}
                onMouseDown={handleMouseDown}
            >
                <img 
                  ref={imageRef}
                  src={currentImage} 
                  alt="Current Thumbnail" 
                  onClick={() => !isSelectionMode && setShowLightbox(true)}
                  draggable={false}
                  className={`relative z-10 w-full h-full object-contain transition-transform duration-300 ${!isSelectionMode && 'cursor-zoom-in'}`}
                />

                {/* Selection Overlay & Popup */}
                {selectedRegion && imageRef.current && (() => {
                     const img = imageRef.current;
                     const rect = img.getBoundingClientRect();
                     const imageRatio = img.naturalWidth / img.naturalHeight;
                     const containerRatio = rect.width / rect.height;

                     let renderWidth = rect.width;
                     let renderHeight = rect.height;
                     let offsetX = 0;
                     let offsetY = 0;

                     if (containerRatio > imageRatio) {
                         renderWidth = rect.height * imageRatio;
                         offsetX = (rect.width - renderWidth) / 2;
                     } else {
                         renderHeight = rect.width / imageRatio;
                         offsetY = (rect.height - renderHeight) / 2;
                     }

                     // Selection Box Coordinates (Relative to Container)
                     const selX = offsetX + (selectedRegion.x * renderWidth);
                     const selY = offsetY + (selectedRegion.y * renderHeight);
                     const selW = selectedRegion.width * renderWidth;
                     const selH = selectedRegion.height * renderHeight;

                     const selectionStyle: React.CSSProperties = {
                         left: selX,
                         top: selY,
                         width: selW,
                         height: selH
                     };

                     // --- POPUP LOGIC ---
                     const MIN_POPUP_WIDTH = 260;
                     const POPUP_HEIGHT = 64; // Approx height of input + margins (increased to prevent clip)
                     const MARGIN = 12;

                     // Target Width
                     // Use min width, but stretch if selection is wider, up to container max
                     let popupW = Math.max(MIN_POPUP_WIDTH, selW);
                     popupW = Math.min(popupW, rect.width - (MARGIN * 2)); // Constrain to container

                     // Target X (Centered on selection)
                     let popupX = selX + (selW / 2) - (popupW / 2);

                     // Clamp X to container
                     popupX = Math.max(MARGIN, Math.min(popupX, rect.width - popupW - MARGIN));

                     // Target Y (Below or Above)
                     // Try below first
                     let popupY = selY + selH + MARGIN;
                     let showBelow = true;

                     // If fits below? (considering footer space etc)
                     if (popupY + POPUP_HEIGHT > rect.height) {
                        // Try above
                        popupY = selY - POPUP_HEIGHT - MARGIN;
                        showBelow = false;
                     }

                     // Final Clamp Y to ensure it is never cut off (even if it means overlapping selection)
                     popupY = Math.max(MARGIN, Math.min(popupY, rect.height - POPUP_HEIGHT - MARGIN));

                     const promptStyle: React.CSSProperties = {
                         left: popupX,
                         top: popupY,
                         width: popupW,
                     };

                     // Arrow Logic
                     // Arrow points to center of selection
                     // Relative to Popup Box
                     const arrowTargetX = (selX + selW / 2) - popupX;
                     // Clamp arrow to within popup radius
                     const ARROW_MARGIN = 16;
                     const arrowSafeX = Math.max(ARROW_MARGIN, Math.min(arrowTargetX, popupW - ARROW_MARGIN));

                     const arrowStyle: React.CSSProperties = {
                        left: arrowSafeX,
                        // Top/Bottom handled by class logic based on showBelow
                     };

                     return (
                         <>
                            {/* The Selection Box */}
                            <div 
                                className="absolute z-30 pointer-events-none"
                                style={selectionStyle}
                            >
                                <div className="absolute inset-0 border-[3px] border-blue-500 bg-blue-500/10 pointer-events-none shadow-[0_0_15px_rgba(59,130,246,0.5)] rounded-lg">
                                    {/* Clear Selection Button */}
                                    <button
                                        onMouseDown={(e) => {
                                            e.stopPropagation();
                                            onRegionChange && onRegionChange(null);
                                        }}
                                        className="absolute -top-3 -right-3 bg-red-500 text-white rounded-full p-1 shadow-sm hover:scale-110 transition-transform pointer-events-auto z-40"
                                        title="Clear Selection"
                                    >
                                        <X size={10} strokeWidth={3} />
                                    </button>
                                    <div className="absolute -top-3 left-2 bg-blue-500 text-white text-[9px] px-1.5 py-0.5 font-bold tracking-wider rounded-full shadow-sm">
                                        EDIT REGION
                                    </div>

                                    {/* Resize Handles */}
                                    <div 
                                        className="absolute top-0 left-0 w-4 h-4 -translate-x-1/2 -translate-y-1/2 bg-white border-2 border-blue-500 rounded-full cursor-nw-resize pointer-events-auto shadow-sm hover:scale-110 transition-transform z-50"
                                        onMouseDown={(e) => handleResizeStart(e, 'tl')}
                                    />
                                    <div 
                                        className="absolute top-0 right-0 w-4 h-4 translate-x-1/2 -translate-y-1/2 bg-white border-2 border-blue-500 rounded-full cursor-ne-resize pointer-events-auto shadow-sm hover:scale-110 transition-transform z-50"
                                        onMouseDown={(e) => handleResizeStart(e, 'tr')}
                                    />
                                    <div 
                                        className="absolute bottom-0 left-0 w-4 h-4 -translate-x-1/2 translate-y-1/2 bg-white border-2 border-blue-500 rounded-full cursor-sw-resize pointer-events-auto shadow-sm hover:scale-110 transition-transform z-50"
                                        onMouseDown={(e) => handleResizeStart(e, 'bl')}
                                    />
                                    <div 
                                        className="absolute bottom-0 right-0 w-4 h-4 translate-x-1/2 translate-y-1/2 bg-white border-2 border-blue-500 rounded-full cursor-se-resize pointer-events-auto shadow-sm hover:scale-110 transition-transform z-50"
                                        onMouseDown={(e) => handleResizeStart(e, 'br')}
                                    />
                                </div>
                            </div>

                            {/* Popup Prompt Input - Sibling to selection, positioned nicely */}
                            {!isDrawing && !isGenerating && (
                                <div 
                                    className="absolute pointer-events-auto z-50 animate-in fade-in slide-in-from-top-1 duration-200"
                                    style={promptStyle}
                                    onMouseDown={(e) => e.stopPropagation()} 
                                >
                                    <form onSubmit={handleRegionPromptSubmit} className="flex gap-1.5 p-1.5 bg-[#1C1C1E] border border-white/10 rounded-xl shadow-2xl shadow-black/80 ring-1 ring-white/5 relative z-10">
                                        <input
                                            type="text"
                                            value={regionPrompt}
                                            onChange={(e) => setRegionPrompt(e.target.value)}
                                            placeholder="Ask AI to edit this area..."
                                            className="flex-1 bg-transparent text-xs text-white placeholder-zinc-500 px-3 py-2 outline-none min-w-0 font-medium"
                                            autoFocus
                                        />
                                        <button 
                                            type="submit"
                                            disabled={!regionPrompt.trim()}
                                            className="bg-blue-600 hover:bg-blue-500 text-white p-2 rounded-lg transition-colors disabled:opacity-50 disabled:bg-white/5"
                                        >
                                            <Send size={12} fill="currentColor" />
                                        </button>
                                    </form>
                                    {/* Arrow */}
                                    <div 
                                        className="absolute w-3 h-3 bg-[#1C1C1E] border-white/10 transform rotate-45 z-0"
                                        style={{
                                            ...arrowStyle,
                                            top: showBelow ? -6 : undefined,
                                            bottom: !showBelow ? -6 : undefined,
                                            borderTop: showBelow ? '1px solid' : 'none',
                                            borderLeft: showBelow ? '1px solid' : 'none',
                                            borderRight: !showBelow ? '1px solid' : 'none',
                                            borderBottom: !showBelow ? '1px solid' : 'none',
                                        }}
                                    />
                                </div>
                            )}
                         </>
                     );
                })()}

                {/* Popup Hint on Hover (Only if not in Selection Mode) */}
                {!isSelectionMode && (
                    <div className="absolute inset-0 z-10 flex items-center justify-center pointer-events-none opacity-0 group-hover/image:opacity-100 transition-opacity duration-300">
                        <div className="bg-black/60 backdrop-blur-sm px-3 py-1.5 rounded-full flex items-center gap-2 text-white/90 text-xs font-medium border border-white/10 translate-y-4 group-hover/image:translate-y-0 transition-transform">
                            <ZoomIn size={14} />
                            <span>Click to expand</span>
                        </div>
                    </div>
                )}
            </div>

            {/* Visual Feedback Overlay (Undo/Redo/Jump) */}
            {feedbackAction && (
                <div className="absolute inset-0 z-40 flex items-center justify-center pointer-events-none animate-in fade-in zoom-in-90 duration-300 fill-mode-forwards">
                    <div className="bg-black/70 backdrop-blur-md px-8 py-6 rounded-3xl flex flex-col items-center gap-3 border border-white/10 shadow-2xl">
                        <div className="p-3 bg-white/10 rounded-full">
                            {feedbackAction.type === 'undo' ? <Undo2 size={32} className="text-white" /> : <Redo2 size={32} className="text-white" />}
                        </div>
                        <div className="text-center">
                            <p className="text-white text-lg font-bold tracking-tight capitalize">
                                {feedbackAction.type === 'undo' ? 'Reverting...' : 'Restoring...'}
                            </p>
                            <p className="text-zinc-400 text-sm font-medium max-w-[200px] truncate">"{feedbackAction.label}"</p>
                        </div>
                    </div>
                </div>
            )}

            {/* MINI GAME OVERLAY (Analysis Phase) */}
            {isAnalyzing && (
                <div className="absolute inset-0 z-50 bg-[#0D0D0D] border-4 border-black">
                    <MiniGame />
                </div>
            )}

            {/* 8-BIT EDITING ANIMATION (Generation Phase - ONLY if not analyzing) */}
            {isGenerating && !isAnalyzing && (
              <div className="absolute inset-0 z-20 flex items-center justify-center bg-black/60 backdrop-blur-sm cursor-default">
                  <EditingAnimation />
              </div>
            )}

            {/* Hover helper for replacing image manually */}
            {!isGenerating && !feedbackAction && !isSelectionMode && (
              <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-all duration-300 z-20 translate-y-2 group-hover:translate-y-0">
                <label className="cursor-pointer bg-black/60 hover:bg-black/80 text-white px-4 py-2.5 rounded-xl backdrop-blur-md flex items-center gap-2 text-xs font-medium border border-white/10 shadow-xl transition-colors">
                    <Upload size={14} />
                    <span>Replace Base</span>
                    <input type="file" className="hidden" accept="image/*" onChange={handleFileChange} />
                </label>
              </div>
            )}

            {/* Helper text for Selection Mode */}
            {isSelectionMode && !selectedRegion && (
                 <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-blue-600 px-5 py-2.5 rounded-full text-white text-xs font-bold border border-white/20 shadow-xl animate-bounce z-40 pointer-events-none">
                     Click and drag to select an area
                 </div>
            )}
          </div>
        ) : (
          /* Empty State / Upload Area */
          <div className="flex flex-col items-center justify-center w-full">
            <div className="text-center w-full max-w-md animate-in fade-in zoom-in-95 duration-500">
                <label 
                className={`
                    block relative cursor-pointer
                    border border-dashed rounded-[2rem] p-10 lg:p-14
                    transition-all duration-300 group
                    ${isDragging 
                    ? 'border-blue-500 bg-blue-500/10 scale-105' 
                    : 'border-white/10 hover:border-white/20 hover:bg-white/5'
                    }
                `}
                >
                <input 
                    type="file" 
                    className="hidden" 
                    accept="image/*"
                    onChange={handleFileChange}
                />

                <div className="flex flex-col items-center gap-6">
                    <div className={`
                        w-20 h-20 rounded-3xl flex items-center justify-center shadow-2xl transition-all duration-300
                        ${isDragging ? 'bg-blue-500 text-white rotate-12 scale-110' : 'bg-[#1C1C1E] text-zinc-400 ring-1 ring-white/10 group-hover:scale-110 group-hover:text-white group-hover:ring-white/20'}
                    `}>
                        {isDragging ? <Upload size={36} /> : <ImageIcon size={36} strokeWidth={1.5} />}
                    </div>

                    <div>
                        <h3 className="text-xl font-semibold text-white mb-2">
                            {isDragging ? 'Drop it here' : 'Start Creating'}
                        </h3>
                        <p className="text-zinc-500 text-sm leading-relaxed">
                            Drag and drop your thumbnail here, <br/> or click to browse files.
                        </p>
                    </div>

                    <span className="text-xs font-medium text-zinc-600 bg-white/5 px-3 py-1 rounded-full border border-white/5">
                        PNG, JPG, WEBP
                    </span>

                    {/* Auto-Analyze Toggle */}
                    {onToggleAutoAnalyze && (
                        <div 
                            onClick={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                                onToggleAutoAnalyze();
                            }}
                            className="flex items-center gap-2 mt-2 cursor-pointer group/toggle p-2 hover:bg-white/5 rounded-lg transition-colors"
                        >
                            <div className={`w-9 h-5 rounded-full p-0.5 transition-colors duration-300 ${autoAnalyzeEnabled ? 'bg-brand-500' : 'bg-zinc-700'}`}>
                                <div className={`w-4 h-4 bg-white rounded-full shadow-sm transition-transform duration-300 ${autoAnalyzeEnabled ? 'translate-x-4' : ''}`} />
                            </div>
                            <div className="flex items-center gap-1.5">
                                <Sparkles size={12} className={autoAnalyzeEnabled ? 'text-brand-400' : 'text-zinc-500'} />
                                <span className={`text-xs font-medium ${autoAnalyzeEnabled ? 'text-zinc-300' : 'text-zinc-500'}`}>Auto-Analyze with AI</span>
                            </div>
                        </div>
                    )}
                </div>
                </label>
            </div>

            {/* Template Selector */}
            <div className="mt-8 w-full max-w-2xl flex flex-col items-center animate-in slide-in-from-bottom-4 duration-500 delay-100">
                <button
                    onClick={(e) => {
                        e.preventDefault();
                        setShowTemplates(!showTemplates);
                    }}
                    className={`
                        flex items-center gap-2 px-5 py-2.5 rounded-full text-xs font-medium transition-all duration-300 border
                        ${selectedTemplate 
                            ? 'bg-zinc-800 text-white border-zinc-700 shadow-lg shadow-black/50' 
                            : 'bg-transparent text-zinc-500 border-transparent hover:bg-white/5 hover:text-zinc-300'
                        }
                    `}
                >
                    {selectedTemplate ? (
                        <>
                            <div className="p-1 rounded bg-brand-500/20 text-brand-400">
                                {React.createElement(TEMPLATES.find(t => t.id === selectedTemplate)?.icon || LayoutTemplate, { size: 12 })}
                            </div>
                            <span className="text-zinc-300">Using: <span className="text-white font-semibold">{TEMPLATES.find(t => t.id === selectedTemplate)?.label}</span></span>
                            <div 
                                onClick={(e) => {
                                    e.stopPropagation();
                                    setSelectedTemplate(null);
                                }}
                                className="ml-1.5 p-0.5 hover:bg-white/20 rounded-full transition-colors text-zinc-500 hover:text-white"
                            >
                                <X size={12} />
                            </div>
                        </>
                    ) : (
                        <>
                            <LayoutTemplate size={14} />
                            <span>Select Style Template (Optional)</span>
                            <ChevronDown size={12} className={`transition-transform duration-300 ${showTemplates ? 'rotate-180' : ''} opacity-50`} />
                        </>
                    )}
                </button>

                <div className={`
                    grid grid-cols-2 md:grid-cols-3 gap-3 px-4 mt-4 w-full transition-all duration-500 ease-[cubic-bezier(0.25,1,0.5,1)] origin-top overflow-hidden
                    ${showTemplates ? 'max-h-96 opacity-100 scale-100' : 'max-h-0 opacity-0 scale-95'}
                `}>
                    {TEMPLATES.map(t => {
                        const isSelected = selectedTemplate === t.id;
                        return (
                            <button 
                                key={t.id}
                                onClick={() => {
                                    setSelectedTemplate(prev => prev === t.id ? null : t.id);
                                }}
                                className={`
                                    group relative p-3 rounded-xl border text-left transition-all duration-200 active:scale-95
                                    ${isSelected 
                                        ? `bg-[#1C1C1E] ${t.border.replace('group-hover:', '')} ring-1 ring-inset ${t.color.replace('text', 'ring')}` 
                                        : `bg-transparent border-white/5 hover:bg-[#1C1C1E] hover:border-white/10`
                                    }
                                `}
                            >
                                <div className="flex items-center gap-3 mb-2">
                                    <div className={`
                                        p-2 rounded-lg transition-colors
                                        ${isSelected ? t.bg.replace('group-hover:', '') : 'bg-white/5 group-hover:bg-white/10'}
                                    `}>
                                        <t.icon size={16} className={isSelected ? t.color : 'text-zinc-400 group-hover:text-white'} />
                                    </div>
                                    <span className={`text-xs font-semibold ${isSelected ? 'text-white' : 'text-zinc-400 group-hover:text-white'}`}>
                                        {t.label}
                                    </span>
                                </div>
                                <p className="text-[10px] text-zinc-600 font-medium pl-1">
                                    {t.desc}
                                </p>
                                {isSelected && (
                                    <div className="absolute top-2 right-2">
                                        <Check size={12} className={t.color} strokeWidth={3} />
                                    </div>
                                )}
                            </button>
                        );
                    })}
                </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

